from typing import List, Dict, Any
import json

class ShortTermMemory:
    """
    Manages session-level context for the Arkanis agent.
    Keeps track of structural interactions: Input, Plan, and Result.
    """
    MAX_LIMIT = 50  # Hard limit for security

    def __init__(self, limit: int = 10):
        self.limit = min(limit, self.MAX_LIMIT)
        self.interactions: List[Dict[str, Any]] = []

    def add_interaction(self, user_input: str, plan: List[Dict[str, Any]], result: str):
        """Adds a complete interaction to history with input validation."""
        if not isinstance(user_input, str) or not isinstance(result, str):
            raise ValueError("Input and result must be strings")

        if not isinstance(plan, list) or not all(isinstance(step, dict) for step in plan):
            raise ValueError("Plan must be a list of dictionaries")

        self.interactions.append({
            "user_input": user_input[:500],  # Truncate to prevent abuse
            "plan": plan[:20],  # Limit steps
            "result": result[:1000]  # Truncate result
        })

        if len(self.interactions) > self.limit:
            self.interactions.pop(0)

    def get_context(self) -> str:
        """Returns optimized context string with token efficiency."""
        if not self.interactions:
            return "Nenhum histórico recente."

        context_lines = ["\n[Histórico Resumido]"]

        # Only keep last 3 interactions for context to save tokens
        for interaction in self.interactions[-3:]:
            tools_used = ", ".join(set(
                step.get('tool', 'unknown') 
                for step in interaction['plan']
            ))

            context_lines.extend([
                f"- Usuário: {interaction['user_input'][:100]}...",
                f"Ferramentas: {tools_used}",
                f"Resultado: {interaction['result'][:150]}...\n"
            ])

        return "\n".join(context_lines).strip()

    def clear(self):
        """Clears the history."""
        self.interactions = []

