from kernel.planner import Planner

class Orchestrator:
    def __init__(self):
        self.agent_bus = AgentBus()
        self.task_engine = TaskEngine()
        self.planner = Planner()
        self.executor = ThreadPoolExecutor(max_workers=10)
        self.active_tasks: Dict[str, Any] = {}

    def start_task_cycle(self, goal: str):
        plan = self.planner.generate_plan(goal)
        for task in plan['tasks']:
            future = self.executor.submit(self._execute_task, task)
            self.active_tasks[task['id']] = future

    def _execute_task(self, task: Dict[str, Any]):
        agent = self.agent_bus.request_agent(task['agent_type'])
        return self.task_engine.execute(agent, task)

    def monitor_system(self):
        return {
            'active_tasks': len(self.active_tasks),
            'agent_usage': self.agent_bus.get_usage_stats()
        }

