import re
import unicodedata

import regex

# non-ASCII letters that are not separated by "NFKD" normalization
ADDITIONAL_DIACRITICS = {
    "œ": "oe",
    "Œ": "OE",
    "ø": "o",
    "Ø": "O",
    "æ": "ae",
    "Æ": "AE",
    "ß": "ss",
    "ẞ": "SS",
    "đ": "d",
    "Đ": "D",
    "ð": "d",
    "Ð": "D",
    "þ": "th",
    "Þ": "th",
    "ł": "l",
    "Ł": "L",
}


def remove_symbols_and_diacritics(s: str, keep=""):
    """
    Replace any other markers, symbols, and punctuations with a space,
    and drop any diacritics (category 'Mn' and some manual mappings)
    """
    return "".join(
        (
            c
            if c in keep
            else (
                ADDITIONAL_DIACRITICS[c]
                if c in ADDITIONAL_DIACRITICS
                else (
                    ""
                    if unicodedata.category(c) == "Mn"
                    else " " if unicodedata.category(c)[0] in "MSP" else c
                )
            )
        )
        for c in unicodedata.normalize("NFKD", s)
    )


def remove_symbols(s: str):
    """
    Replace any other markers, symbols, punctuations with a space, keeping diacritics
    """
    return "".join(
        " " if unicodedata.category(c)[0] in "MSP" else c
        for c in unicodedata.normalize("NFKC", s)
    )


class BasicTextNormalizer:
    def __init__(self, remove_diacritics: bool = False, split_letters: bool = False):
        self.clean = (
            remove_symbols_and_diacritics if remove_diacritics else remove_symbols
        )
        self.split_letters = split_letters

    def __call__(self, s: str):
        s = s.lower()
        s = re.sub(r"[<\[][^>\]]*[>\]]", "", s)  # remove words between brackets
        s = re.sub(r"\(([^)]+?)\)", "", s)  # remove words between parenthesis
        s = self.clean(s)

        if self.split_letters:
            s = " ".join(regex.findall(r"\X", s, regex.U))

        s = re.sub(
            r"\s+", " ", s
        )  # replace any successive whitespace characters with a space

        return s

# Hierarquia LLMHandler com métodos handle_request()
class LLMHandler:
    def __init__(self, successor=None):
        self._successor = successor

    def handle_request(self, prompt):
        if self.can_process(prompt):
            return self.process(prompt)
        elif self._successor:
            return self._successor.handle_request(prompt)

    @abstractmethod
    def can_process(self, prompt):
        pass

    @abstractmethod
    def process(self, prompt):
        pass

# Implementações Especializadas
class GPT4Handler(LLMHandler):
    def can_process(self, prompt):
        return prompt.complexity > 0.8

    def process(self, prompt):
        return llm_client.call('gpt-4', prompt)

class ClaudeHandler(LLMHandler):
    def can_process(self, prompt):
        return prompt.creative_boost_needed

    def process(self, prompt):
        return llm_client.call('claude-v1', prompt)

# Configuração Chain
chain = GPT4Handler(ClaudeHandler())
result = chain.handle_request(user_prompt)

import os
import sys
import glob
from typing import Dict, List

import jiwer
from normalizers import EnglishTextNormalizer


def decode_hypothesis(b: bytes) -> str:
    try:
        return b.decode('windows-1252')
    except UnicodeDecodeError:
        return b.decode('utf-8', errors='ignore')


def get_reference() -> Dict[str, str]:
    ref = {}
    for path in glob.glob("speech-datasets/earnings21/transcripts/nlp_references/*.nlp"):
        if not os.path.exists(path):
            raise FileNotFoundError(f"Arquivo de referência não encontrado: {path}")
        code = os.path.basename(path).replace(".nlp", "")
        buf = []
        with open(path) as fp:
            fp.readline()
            for line in fp:
                token = line.split("|", maxsplit=1)[0]
                buf.append(token)
            ref[code] = " ".join(buf)
    return ref


def get_hypothesis() -> Dict[str, str]:
    hyp = {}
    for path in glob.glob("speech-datasets/earnings21/media/*.mp3.txt"):
        if not os.path.exists(path):
            raise FileNotFoundError(f"Arquivo de hipótese não encontrado: {path}")
        with open(path, 'rb') as fp:
            text = decode_hypothesis(fp.read()).strip()
        code = os.path.basename(path).replace(".mp3.txt", "")
        hyp[code] = text
    return hyp


def get_codes(metadata_csv: str) -> List[str]:
    if not os.path.exists(metadata_csv):
        raise FileNotFoundError(f"Arquivo de metadados não encontrado: {metadata_csv}")
    codes = []
    with open(metadata_csv) as fp:
        fp.readline()
        for line in fp:
            codes.append(line.split(",")[0])
    return sorted(codes)


def main() -> int:
    if len(sys.argv) < 2:
        print(f"Usage: {sys.argv[0]} METADATA_CSV", file=sys.stderr)
        return 1

    try:
        metadata_csv = sys.argv[1]
        normalizer = EnglishTextNormalizer()

        ref_orig = get_reference()
        hyp_orig = get_hypothesis()

        ref_clean = []
        hyp_clean = []

        for code in get_codes(metadata_csv):
            ref_clean.append(normalizer(ref_orig[code]))
            hyp_clean.append(normalizer(hyp_orig[code]))

        wer = jiwer.wer(ref_clean, hyp_clean)
        print(f"WER: {wer * 100:.2f}%")
    except FileNotFoundError as e:
        print(f"Erro: {str(e)}", file=sys.stderr)
        return 1
    except Exception as e:
        print(f"Erro inesperado: {str(e)}", file=sys.stderr)
        return 1

    return 0


if __name__ == "__main__":
    sys.exit(main())

import re
import unicodedata
import functools
import regex

# non-ASCII letters that are not separated by "NFKD" normalization
ADDITIONAL_DIACRITICS = {
    "œ": "oe",
    "Œ": "OE",
    "ø": "o",
    "Ø": "O",
    "æ": "ae",
    "Æ": "AE",
    "ß": "ss",
    "ẞ": "SS",
    "đ": "d",
    "Đ": "D",
    "ð": "d",
    "Ð": "D",
    "þ": "th",
    "Þ": "th",
    "ł": "l",
    "Ł": "L",
}

# Compile regex patterns once
BRACKET_PATTERN = re.compile(r"[<\[]][^>\]]*[>\]]")
PARENTHESIS_PATTERN = re.compile(r"\(([^)]+?)\)")
WHITESPACE_PATTERN = re.compile(r"\s+")

# Cache for unicodedata.category
@functools.lru_cache(maxsize=4096)
def _get_category(char):
    return unicodedata.category(char)


def remove_symbols_and_diacritics(s: str, keep=""):
    """
    Replace any other markers, symbols, and punctuations with a space,
    and drop any diacritics (category 'Mn' and some manual mappings)
    """
    return "".join(
        (
            c
            if c in keep
            else (
                ADDITIONAL_DIACRITICS[c]
                if c in ADDITIONAL_DIACRITICS
                else (
                    ""
                    if _get_category(c) == "Mn"
                    else " " if _get_category(c)[0] in "MSP" else c
                )
            )
        )
        for c in unicodedata.normalize("NFKD", s)
    )


def remove_symbols(s: str):
    """
    Replace any other markers, symbols, punctuations with a space, keeping diacritics
    """
    return "".join(
        " " if _get_category(c)[0] in "MSP" else c
        for c in unicodedata.normalize("NFKC", s)
    )


class BasicTextNormalizer:
    def __init__(self, remove_diacritics: bool = False, split_letters: bool = False):
        self.clean = (
            remove_symbols_and_diacritics if remove_diacritics else remove_symbols
        )
        self.split_letters = split_letters

    def __call__(self, s: str):
        s = s.lower()
        s = BRACKET_PATTERN.sub("", s)  # remove words between brackets
        s = PARENTHESIS_PATTERN.sub("", s)  # remove words between parenthesis
        s = self.clean(s).lower()

        if self.split_letters:
            s = " ".join(regex.findall(r"\X", s, regex.U))

        s = WHITESPACE_PATTERN.sub(" ", s)  # replace any successive whitespace characters with a space

        return s

