def expand_includes(shader, input_dir, already_included=None):
    """
    Replace #include "file" lines in the text with the contents of that file.
    Searches for files relative to input_dir. Prevents circular includes.
    """
    if already_included is None:
        already_included = set()

    include_pattern = re.compile(r'^\s*#include\s+"([^"]+)"\s*$', re.MULTILINE)

    def replacer(match):
        fname = match.group(1)
        if fname in already_included:
            raise RuntimeError(f"Circular include detected for file: {fname}")

        file_path = os.path.join(input_dir, fname)
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"Included file not found: {file_path}")

        already_included.add(fname)
        with open(file_path, "r", encoding="utf-8") as f:
            included_code = f.read()

        # Recursively expand includes while tracking included files
        return expand_includes(included_code, input_dir, already_included)

    return include_pattern.sub(replacer, shader)

