logger = logging.getLogger(__name__)

class ToolRegistry:
    """
    A singleton class to manage the registration and discovery of tools.
    Thread-safe implementation with proper type hints.
    """
    _instance = None
    _tools: Dict[str, BaseTool] = {}
    _lock = threading.Lock()

    def __new__(cls):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super(ToolRegistry, cls).__new__(cls)
        return cls._instance

    def register(self, tool: BaseTool) -> None:
        """Register a tool instance."""
        with self._lock:
            self._tools[tool.name] = tool
            logger.info(f"Tool registered: {tool.name}")

    def get_tool(self, name: str) -> Optional[BaseTool]:
        """Retrieve a tool by name."""
        with self._lock:
            return self._tools.get(name)

    def list_tools(self) -> Dict[str, str]:
        """Return a dictionary of tool names and their descriptions."""
        with self._lock:
            return {name: tool.description for name, tool in self._tools.items()}

    def get_all_tools(self) -> List[BaseTool]:
        """Return a list of all registered tool instances."""
        with self._lock:
            return list(self._tools.values())

# Global registry instance
registry = ToolRegistry()

