        self.goal_planner = goal_planner
        self.agent_bus = agent_bus
        self.goal_manager = goal_manager
        self.strategy_cache = {}

    def sync_goals_and_tasks(self):
        "Sincroniza objetivos e tarefas entre módulos"
        goals = self.goal_manager.get_active_goals()
        self.task_engine.update_tasks_based_on_goals(goals)

    def evaluate_and_route(self, agent_request):
        "Avalia solicitações de agentes e roteia para o módulo apropriado"
        if agent_request['type'] == 'task':
            return self.task_engine.process_task(agent_request)
        elif agent_request['type'] == 'goal':
            return self.goal_planner.generate_plan(agent_request)
        elif agent_request['type'] == 'communication':
            return self.agent_bus.broadcast(agent_request)

    def execute_strategy(self, strategy_name):
        "Executa estratégias previamente armazenadas"
        if strategy_name in self.strategy_cache:
            return self.strategy_cache[strategy_name].execute()
        else:
            raise ValueError(f'Estratégia {strategy_name} não encontrada no cache.')

