class ModuleOrchestrator:
    def __init__(self):
        self.modules = {}
        self.handlers = {}

    def register_module(self, module_name, module_instance):
        self.modules[module_name] = module_instance

    def register_handler(self, event_type, handler_function):
        if event_type not in self.handlers:
            self.handlers[event_type] = []
        self.handlers[event_type].append(handler_function)

    def dispatch_event(self, event_type, event_data=None):
        if event_type in self.handlers:
            for handler in self.handlers[event_type]:
                handler(event_data)

