            with open(path, 'r', encoding='utf-8') as fp:
                fp.readline()
                for line in fp:
                    token = line.split("|", maxsplit=1)[0]
                    buf.append(token)
                ref[code] = " ".join(buf)
    except Exception as e:
        print(f"Erro ao ler arquivo de referência: {e}", file=sys.stderr)
    return ref

def get_hypothesis():
    hyp = {}
    try:
        for path in glob.glob("speech-datasets/earnings21/media/*.mp3.txt"):
            with open(path, 'rb') as fp:
                text = decode_hypothesis(fp.read()).strip()
            code = os.path.basename(path).replace(".mp3.txt", "")
            hyp[code] = text
    except Exception as e:
        print(f"Erro ao ler hipótese: {e}", file=sys.stderr)
    return hyp

def get_codes(metadata_csv):
    codes = []
    try:
        with open(metadata_csv, 'r', encoding='utf-8') as fp:
            fp.readline()
            for line in fp:
                codes.append(line.split(",")[0])
    except Exception as e:
        print(f"Erro ao ler CSV de metadados: {e}", file=sys.stderr)
    return sorted(codes)

def main():
    if len(sys.argv) < 2:
        print("Usage: %s METADATA_CSV" % sys.argv[0], file=sys.stderr)
        return 1

    metadata_csv = sys.argv[1]
    normalizer = EnglishTextNormalizer()

    ref_orig = get_reference()
    hyp_orig = get_hypothesis()

    ref_clean = []
    hyp_clean = []

    try:
        for code in get_codes(metadata_csv):
            ref_clean.append(normalizer(ref_orig[code]))
            hyp_clean.append(normalizer(hyp_orig[code]))

        wer = jiwer.wer(ref_clean, hyp_clean)
        print(f"WER: {wer * 100:.2f}%")
    except KeyError as e:
        print(f"Erro de chave no dicionário: {e}", file=sys.stderr)
        return 1
    except Exception as e:
