import re

class Executor:
    """
    Executes the planned steps using the registered tools.
    Supports Result Propagation (Piping) between steps using {{ tool_name }} syntax.
    """

    def _sanitize_input(self, input_str: str) -> str:
        """Sanitize inputs to prevent injection attacks"""
        if not isinstance(input_str, str):
            return input_str
        return re.sub(r'[^\w\s{}-]', '', input_str)

    def _resolve_placeholders(self, value: str, execution_context: Dict) -> str:
        """Handle all placeholder substitutions in a secure way"""
        if not isinstance(value, str):
            return value

        sanitized_value = self._sanitize_input(value)

        for prev_tool, prev_result in execution_context.items():
            alias = prev_tool.replace('get_', '')
            pattern = rf'{{{{?\s*({re.escape(prev_tool)}|{re.escape(alias)})\s*}}}}?'

            def replace_func(match):
                processed_result = prev_result
                if prev_tool == "get_current_datetime" and isinstance(prev_result, str):
                    try:
                        import json
                        data = json.loads(prev_result)
                        processed_result = data.get("datetime", prev_result)
                    except:
                        pass
                return str(processed_result)

            sanitized_value = re.sub(pattern, replace_func, sanitized_value)

        return sanitized_value

    def execute_plan(self, plan: List[Dict[str, Any]]) -> List[str]:
        results = []
        execution_context = {}

        rprint("\n[bold yellow]--- Iniciando Execução ---[/bold yellow]")

        for step in plan:
            if not isinstance(step, dict):
                results.append(f"Error: Invalid step format - {step}")
                continue

            tool_name = step.get("tool")
            args = step.get("args", {})

            if not tool_name:
                results.append("Error: Missing 'tool' in step")
                continue

            # Process all arguments for placeholders
            try:
                args = {k: self._resolve_placeholders(v, execution_context) 
                       for k, v in args.items()}
            except Exception as e:
                results.append(f"Error processing placeholders: {str(e)}")
                continue

            tool = registry.get_tool(tool_name)
            if not tool:
                rprint(f"[bold red][Executor] Erro:[/bold red] Ferramenta '{tool_name}' não encontrada.")
                results.append(f"Error: Tool '{tool_name}' not found.")
                continue

            try:
                rprint(f"[bold yellow][Executor] Executando:[/bold yellow] {tool_name}")
                result = tool.execute(**args)
                rprint(f"[bold green][Executor] Concluído:[/bold green] {tool_name}")
                execution_context[tool_name] = result
                results.append(result)
            except Exception as e:
                error_msg = f"Error in tool '{tool_name}': {str(e)}"
                rprint(f"[bold red][Executor] Erro:[/bold red] {error_msg}")
                results.append(error_msg)

        rprint("[bold green]--- Execução Finalizada ---[/bold green]\n")
        return results

class AskLLMTool(BaseTool):
    """
    A internal tool that allows the agent to delegate complex text processing, 
    summarization, or extraction to the LLM during execution.
    """
    def __init__(self):
        api_key = os.environ.get("OPENROUTER_API_KEY")
        if not api_key:
            raise ValueError("OPENROUTER_API_KEY environment variable not set")
        # We need an LLM Client specifically for the tool layer
        self.llm = LLMClient(api_key=api_key)

    @property
    def name(self) -> str: return "ask_llm"

    @property
    def description(self) -> str: 
        return "Process, summarize, or extract information from given text. Useful as a middle-step after fetching data."

    @property
    def arguments(self) -> Dict[str, str]:
        return {
            "instruction": "The command for the LLM (e.g., 'Summarize this in 3 bullet points').",
            "text_content": "The raw text to be processed (often piped from another tool)."
        }

    def execute(self, **kwargs) -> str:
        instruction = kwargs.get("instruction")
        text_content = kwargs.get("text_content")

        if not instruction or not text_content:
            return "Error: Missing instruction or text_content."

        system_prompt = "You are a sub-processor for ARKANIS OS. Process the user's text strictly according to the instruction. Return ONLY the processed text, without conversational fillers."
        user_prompt = f"INSTRUCTION:\n{instruction}\n\nTEXT TO PROCESS:\n{text_content}"

        try:
            response = self.llm.generate(system_prompt=system_prompt, user_prompt=user_prompt)
            if response:
                return response
            return "Error: LLM returned empty response."
        except Exception as e:
            return f"Error connecting to LLM: {str(e)}"

