from abc import ABC, abstractmethod
from typing import Any, Dict, Optional

class BaseTool(ABC):
    """
    Abstract base class for all Arkanis tools.
    Every tool must implement name, description, arguments, and execute().

    Example:
        class MyTool(BaseTool):
            @property
            def name(self) -> str:
                return 'my_tool'

            @property
            def description(self) -> str:
                return 'Performs specific operation'

            @property
            def arguments(self) -> Dict[str, str]:
                return {
                    'param1': 'Description of parameter 1',
                    'param2': 'Description of parameter 2'
                }

            def execute(self, **kwargs) -> Any:
                # Implementation logic here
                return some_result
    """

    @property
    @abstractmethod
    def name(self) -> str:
        """The unique identifier name of the tool.

        Returns:
            str: The tool's name that will be used for identification.
        """
        pass

    @property
    @abstractmethod
    def description(self) -> str:
        """Brief explanation of what the tool does.

        Returns:
            str: A clear description of the tool's purpose and functionality.
        """
        pass

    @property
    @abstractmethod
    def arguments(self) -> Dict[str, str]:
        """Dictionary mapping argument names to their descriptions.

        Returns:
            Dict[str, str]: A dictionary where keys are argument names and values are
                            their descriptions and expected types.
        """
        pass

    @abstractmethod
    def execute(self, **kwargs) -> Optional[Any]:
        """The main logic of the tool.

        Args:
            **kwargs: Variable keyword arguments passed to the tool.

        Returns:
            Optional[Any]: The result of the tool's execution, if applicable.
        """
        pass

def gb_converter(value, unit):
    """Converts bytes to GB based on the unit multiplier."""
    return value / unit

def get_ram_gb():
    """Returns available RAM in GB."""
    system = platform.system()
    try:
        if system == "Linux":
            with open("/proc/meminfo", "r") as f:
                for line in f:
                    if "MemTotal" in line:
                        return gb_converter(int(line.split()[1]), 1024**2)
        elif system == "Darwin":
            res = subprocess.run(["sysctl", "hw.memsize"], capture_output=True, text=True)
            return gb_converter(int(res.stdout.split(":")[1].strip()), 1024**3)
        elif system == "Windows":
            res = subprocess.run(["wmic", "ComputerSystem", "get", "TotalPhysicalMemory"], capture_output=True, text=True)
            mem = res.stdout.splitlines()[2].replace(" ", "")
            return gb_converter(int(mem), 1024**3)
    except (FileNotFoundError, subprocess.SubprocessError, IndexError, ValueError) as e:
        print(f"Error fetching RAM: {e}", file=sys.stderr)
    return 4.0 # Default fallback

