from typing import Dict, List, Any

MEM_FILE = os.path.join(os.path.dirname(os.path.dirname(os.path.abspath(__file__))), "..", "data", "long_term_memory.json")

logger = logging.getLogger('ArkanisV3.LongTermMemory')

class LongTermMemory:
    """
    Persistent long-term memory storage for ARKANIS V3.
    Stores and retrieves user preferences, important facts, and recurring tasks.
    """
    def __init__(self):
        self._lock = threading.Lock()
        self.data: Dict[str, List[str]] = {
            "preferences": [],
            "facts": [],
            "recurrent_tasks": []
        }
        self.max_items_per_category = 20
        self._load()

    def _ensure_dir(self):
        try:
            os.makedirs(os.path.dirname(MEM_FILE), exist_ok=True)
        except Exception as e:
            logger.error(f'Failed to create directory structure: {e}', exc_info=True)

    def _load(self):
        with self._lock:
            if os.path.exists(MEM_FILE):
                try:
                    with open(MEM_FILE, "r", encoding="utf-8") as f:
                        loaded_data = json.load(f)
                        # Merge to ensure keys exist
                        for k in self.data.keys():
                            if k in loaded_data:
                                self.data[k] = loaded_data[k]
                    logger.info('Long-term memory loaded successfully')
                except Exception as e:
                    logger.error(f'Failed to load long term memory: {e}', exc_info=True)

    def _save(self):
        self._ensure_dir()
        with self._lock:
            try:
                with open(MEM_FILE, "w", encoding="utf-8") as f:
                    json.dump(self.data, f, indent=4, ensure_ascii=False)
                logger.debug('Long-term memory saved successfully')
            except Exception as e:
                logger.error(f'Failed to save long term memory: {e}', exc_info=True)

    def add_memory(self, category: str, content: str) -> bool:
        """Add a new memory to a category, preventing exact duplicates."""
        if category not in self.data:
            logger.warning(f'Attempted to add memory to invalid category: {category}')
            return False

        try:
            content_clean = content.strip()
            with self._lock:
                # Prevent exact duplicate
                if content_clean in self.data[category]:
                    logger.debug(f'Duplicate memory content skipped: {content}')
                    return True

                self.data[category].append(content_clean)
                # Enforce size limit by popping oldest
                if len(self.data[category]) > self.max_items_per_category:
                    removed = self.data[category].pop(0)
                    logger.debug(f'Removed oldest memory item due to limit: {removed}')

            self._save()
            logger.info(f'New memory added to category {category}: {content}')
            return True
        except Exception as e:
            logger.error(f'Failed to add memory: {e}', exc_info=True)
            return False

    def get_formatted_memory(self) -> str:
        """Returns the long-term memory formatted for the LLM context."""
        with self._lock:
            out = []
            if self.data["preferences"]:
                out.append("[PREFERÊNCIAS DO USUÁRIO]")
                out.extend([f"- {p}" for p in self.data["preferences"]])
            if self.data["facts"]:
                out.append("[FATOS IMPORTANTES]")
                out.extend([f"- {f}" for f in self.data["facts"]])
            if self.data["recurrent_tasks"]:
                out.append("[TAREFAS RECORRENTES]")
                out.extend([f"- {t}" for t in self.data["recurrent_tasks"]])

            if not out:
                logger.debug('Returning empty formatted memory')
                return ""
            return "\n".join(out)

# Global singleton
long_term_memory = LongTermMemory()

from typing import List, Dict, Any
from collections import deque

class ShortTermMemory:
    """
    Manages session-level context for the Arkanis agent.
    Keeps track of structural interactions: Input, Plan, and Result.
    """
    def __init__(self, limit: int = 10):
        self.limit = limit
        self.interactions = deque(maxlen=limit)

    def add_interaction(self, user_input: str, plan: List[Dict[str, Any]], result: str):
        """Adds a complete interaction to history."""
        self.interactions.append({
            "user_input": user_input,
            "plan": plan,
            "result": result
        })

    def get_context(self) -> str:
        """Returns the current history formatted as a string for the LLM prompt."""
        if not self.interactions:
            return "Nenhum histórico recente."

        context_lines = []
        for i, interaction in enumerate(self.interactions, 1):
            context_lines.append(f"[Interação Anterior {i}]")
            context_lines.append(f"-> Usuário: {interaction['user_input']}")
            # Extract just the tools used to avoid huge JSON strings consuming context token limits
            tools_used = [step.get('tool', 'unknown') for step in interaction['plan']]
            context_lines.append(f"-> Ferramentas do Agente: {tools_used}")
            context_lines.append(f"-> Resultado: {interaction['result']}
")

        return "\n".join(context_lines).strip()

    def clear(self):
        """Clears the history."""
        self.interactions.clear()

# Global instance for easy access
session_memory = ShortTermMemory(limit=10)
